function head(title,sub,action=''){if(page==='accounts'&&title==='支付方式'){title='账户';sub='管理账户余额、支付平台和月付方式'}return `<div class="page-head"><div><h1>${title}</h1><p>${sub}</p></div>${action}</div>`}
function content(){if(page==='add')return addPage();if(page==='records')return recordsPage();if(page==='stats')return statsPage();if(page==='debts')return debtsPage();if(page==='budget')return budgetPage();if(page==='accounts')return paymentsPage();if(page==='my'||page==='settings')return settingsPage();if(page==='profile')return profilePage();return homePage()}
function homePage(){const d=debt().reduce((s,t)=>s+t.amount,0),previous=monthlyFinance(previousMonth()),filterButton=(type,label)=>`<button type="button" class="card-filter-button" data-page="records" data-records-filter="${type}" title="${label}" aria-label="${label}">›</button>`;return `${head(`下午好，${escapeHtml(state.profile.name)} 👋`,'今天也要照顾好自己的钱包','<button class="primary" data-page="add">＋ 记一笔</button>')}<div class="section-heading account-overview-heading"><div><h2>账户总览</h2><p>余额、存款与本月财务情况</p></div></div><div class="cards dashboard-cards"><div class="card dashboard-card income-card"><div class="card-heading"><b>本月收入</b>${filterButton('income','查看本月收入明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">💵</i><i class="icon-v2">💰</i></span><div class="money">${money(income())}</div></div>${monthTrend(income(),previous.income,true)}</div><div class="card dashboard-card orange expense-card"><div class="card-heading"><b>本月花销</b>${filterButton('expense','查看本月花销明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">🧾</i><i class="icon-v2">🛒</i></span><div class="money">${money(expense())}</div></div>${monthTrend(expense(),previous.expense,false)}</div><div class="card dashboard-card ${remainingBudget()<0?'red':'green'} budget-card"><div class="card-heading"><b>本月剩余预算</b></div><div class="card-value"><span class="metric-icon"><i class="icon-v1">🎯</i><i class="icon-v2">🧮</i></span><div class="money">${money(remainingBudget())}</div></div><span class="sub">预算总额：${money(totalBudget())}</span></div><div class="card dashboard-card red debt-card"><div class="card-heading"><b>待还款</b>${filterButton('debt','查看本月待还款明细')}</div><div class="card-value"><span class="metric-icon"><i class="icon-v1">⏳</i><i class="icon-v2">💳</i></span><div class="money">${money(d)}</div></div><span class="sub">待还款笔数：${debt().length} 笔</span></div></div>${accountOverview()}<div class="grid2"><section class="panel"><div class="panel-title"><span>📊 类别预算 · 共 ${state.categories.length} 类</span><button class="secondary" data-page="budget">管理预算</button></div><div class="panel-body home-scroll-body">${state.categories.map(budgetLine).join('')}</div></section><section class="panel"><div class="panel-title"><span>📝 明细 · 共 ${state.transactions.length} 笔</span><button class="secondary" data-page="records">查看全部</button></div><div class="panel-body home-scroll-body">${sortedTransactions(state.transactions).map(txLine).join('')||'<div class="empty">还没有收支记录</div>'}</div></section></div>`}
function budgetLine(c){let u=used(c),b=Number(state.budgets[c]),left=b-u,p=Math.min(100,u/b*100||0);return `<div class="budget-row"><div class="row-top"><span>${categoryIcon(c)} ${escapeHtml(c)}</span><span class="${left<0?'budget-over':''}">剩余 ${money(left)}</span></div><div class="track"><div class="fill ${p>80?'warn':''}" style="width:${p}%"></div></div><div class="budget-meta">已用 ${money(u)} / 预算 ${money(b)}</div></div>`}
function txLine(t,actions=false){return `<div class="tx ${actions?'tx-manage':''}"><span class="tx-icon">${t.type==='income'?'💰':categoryIcon(t.category)}</span><span><b>${escapeHtml(t.note||t.category)}</b><small>${t.date.slice(5)} ${t.time} · ${escapeHtml(t.platform)}${!t.repaid?' · 待还款':''}</small></span><span class="tx-amount ${t.type==='income'?'in':''}">${t.type==='income'?'+':'−'}${money(t.amount)}</span>${actions?`<span class="tx-actions"><button class="icon-button" data-edit-tx="${t.id}" title="编辑记录">✎</button><button class="icon-button danger-icon" data-delete-tx="${t.id}" title="删除记录">×</button></span>`:''}</div>`}
function platformButtons(kind){return state.platforms.filter(p=>p.kind===kind).map((p,i)=>`<button type="button" data-value="${escapeHtml(p.name)}" class="${i===0?'selected':''}">${escapeHtml(p.name)}</button>`).join('')}
function addPage(){let hasCredit=creditPlatforms().length>0,addButton=target=>`<button type="button" class="primary field-add-button" data-page="${target}">增加＋</button>`;return `${head('记一笔','日期与时间会自动填充')}<section class="panel add-panel"><div class="panel-title">✏️ 新增记录</div><div class="panel-body"><form id="txForm"><div class="choice" id="typeChoice"><button type="button" class="selected" data-value="expense">花销</button><button type="button" data-value="income">收入</button></div><div class="form-grid" style="margin-top:14px"><div class="field full"><label>金额</label><input class="amount-input" id="amount" type="number" min="0.01" step="0.01" placeholder="¥ 0.00" required></div><div class="field full" id="catField"><div class="field-label-row"><label>类别</label>${addButton('budget')}</div><div class="choice" id="catChoice">${state.categories.map((c,i)=>`<button type="button" data-value="${escapeHtml(c)}" class="${i===0?'selected':''}">${categoryIcon(c)} ${escapeHtml(c)}</button>`).join('')}</div></div><div class="field date-field"><label>日期</label><input id="date" type="date" value="${today()}"></div><div class="field time-field"><label>时间</label><input id="time" type="time" value="${new Date().toTimeString().slice(0,5)}"></div><div class="field full" id="payModeField"><div class="field-label-row"><label>付款方式</label>${addButton('accounts')}</div><div class="choice segmented" id="payModeChoice"><button type="button" data-value="account" class="selected">余额支付</button><button type="button" data-value="credit" ${hasCredit?'':'disabled'}>月付</button></div></div><div class="field full" id="accountPlatformField"><div class="field-label-row"><label id="accountPlatformLabel">支付平台</label>${addButton('accounts')}</div><div class="choice" id="accountPlatformChoice">${platformButtons('account')}</div></div><div class="field full hidden" id="creditPlatformField"><div class="field-label-row"><label>选择月付平台</label>${addButton('accounts')}</div><div class="choice" id="creditPlatformChoice">${platformButtons('credit')}</div></div><div class="field full"><label>备注</label><textarea id="note" rows="2" placeholder="写点什么（可选）"></textarea></div></div><div class="form-actions"><button type="button" class="primary" id="saveTransaction">保存记录</button></div></form></div></section>`}
function recordsPage(){let selected=recordsMonth||currentMonth(),categories=[...new Set([...state.categories,...state.transactions.filter(t=>t.type==='expense').map(t=>t.category)])],list=state.transactions.filter(t=>t.date.startsWith(selected));if(recordsType==='income')list=list.filter(t=>t.type==='income');if(recordsType==='expense')list=list.filter(t=>t.type==='expense');if(recordsType==='debt')list=list.filter(t=>t.type==='expense'&&!t.repaid&&platformKind(t.platform)==='credit');if(recordsCategory!=='all')list=list.filter(t=>t.category===recordsCategory);list=sortedTransactions(list);return `${head('收支明细','组合月份、类型和类别筛选所需记录','<button class="primary" data-page="add">＋ 记一笔</button>')}<form class="filter-bar records-filter-bar" id="recordsFilterForm"><label>月份<input id="recordsMonth" type="month" value="${selected}" required></label><label>类型<select id="recordsType"><option value="all" ${recordsType==='all'?'selected':''}>全部</option><option value="expense" ${recordsType==='expense'?'selected':''}>支出</option><option value="income" ${recordsType==='income'?'selected':''}>收入</option><option value="debt" ${recordsType==='debt'?'selected':''}>待还款</option></select></label><label>类别<select id="recordsCategory"><option value="all">全部类别</option>${categories.map(c=>`<option value="${escapeHtml(c)}" ${recordsCategory===c?'selected':''}>${categoryIcon(c)} ${escapeHtml(c)}</option>`).join('')}</select></label><button class="primary" id="applyRecordsFilter">筛选</button><span>共 ${list.length} 笔</span></form><section class="panel"><div class="panel-title"><span>📋 ${monthName(selected)}</span><span>收入 ${money(list.filter(t=>t.type==='income').reduce((s,t)=>s+t.amount,0))} · 支出 ${money(list.filter(t=>t.type==='expense').reduce((s,t)=>s+t.amount,0))}</span></div><div class="panel-body">${list.length?list.map(t=>txLine(t,true)).join(''):'<div class="empty">没有符合筛选条件的记录</div>'}</div></section>`}
function statsPage(){let list=statsTransactions(),incomeTotal=list.filter(t=>t.type==='income').reduce((s,t)=>s+t.amount,0),expenseTotal=list.filter(t=>t.type==='expense').reduce((s,t)=>s+t.amount,0),maxTotal=Math.max(incomeTotal,expenseTotal,1),groups={};list.filter(t=>t.type==='expense').forEach(t=>groups[t.category]=(groups[t.category]||0)+t.amount);let parts=Object.entries(groups).sort((a,b)=>b[1]-a[1]),colors=['#3478d8','#e85d4a','#43a541','#f1a22c','#17a2a8','#9b59b6','#d46f9a','#607d3b','#795548','#63748a'],cursor=0,gradient=parts.length?parts.map(([c,v],i)=>{let start=cursor;cursor+=v/expenseTotal*100;return `${colors[i%colors.length]} ${start}% ${cursor}%`}).join(','):'#e1dfd3 0 100%';return `${head('收支统计','按月、按年或自定义时间查看财务情况')}<section class="panel stats-filter"><div class="panel-body"><div class="choice segmented" id="statsMode"><button data-value="month" class="${statsMode==='month'?'selected':''}">按月</button><button data-value="year" class="${statsMode==='year'?'selected':''}">按年</button><button data-value="custom" class="${statsMode==='custom'?'selected':''}">自定义</button></div><div class="stats-date-controls"><label class="${statsMode==='month'?'':'hidden'}">月份<input id="statsMonth" type="month" value="${statsMonth||currentMonth()}"></label><label class="${statsMode==='year'?'':'hidden'}">年份<input id="statsYear" type="number" min="2000" max="2100" value="${statsYear||today().slice(0,4)}"></label><label class="${statsMode==='custom'?'':'hidden'}">开始<input id="statsStart" type="date" value="${statsStart||`${currentMonth()}-01`}"></label><label class="${statsMode==='custom'?'':'hidden'}">结束<input id="statsEnd" type="date" value="${statsEnd||today()}"></label></div></div></section><div class="cards stats-summary"><div class="card green"><span class="label">${statsPeriodLabel()}收入</span><div class="money">${money(incomeTotal)}</div></div><div class="card orange"><span class="label">支出</span><div class="money">${money(expenseTotal)}</div></div><div class="card ${incomeTotal-expenseTotal<0?'red':'green'}"><span class="label">结余</span><div class="money">${money(incomeTotal-expenseTotal)}</div></div><div class="card"><span class="label">记录数量</span><div class="money">${list.length}</div></div></div><div class="stats-grid"><section class="panel"><div class="panel-title">📊 收支对比</div><div class="panel-body"><div class="bar-chart"><div class="bar-item"><div class="bar-value">${money(incomeTotal)}</div><div class="bar-column income-bar" style="height:${Math.max(6,incomeTotal/maxTotal*100)}%"></div><b>收入</b></div><div class="bar-item"><div class="bar-value">${money(expenseTotal)}</div><div class="bar-column expense-bar" style="height:${Math.max(6,expenseTotal/maxTotal*100)}%"></div><b>支出</b></div></div></div></section><section class="panel"><div class="panel-title">🍰 支出类别</div><div class="panel-body pie-layout"><div class="pie" style="background:conic-gradient(${gradient})"><span>${expenseTotal?money(expenseTotal):'暂无支出'}</span></div><div class="pie-legend">${parts.length?parts.map(([c,v],i)=>`<div><i style="background:${colors[i%colors.length]}"></i><span>${categoryIcon(c)} ${escapeHtml(c)}</span><b>${money(v)} · ${(v/expenseTotal*100).toFixed(1)}%</b></div>`).join(''):'<div class="empty">所选时间暂无支出</div>'}</div></div></section></div>`}
function debtsPage(){let groups=creditPlatforms().map(p=>p.name),next=nextRepayment();return `${head('待还款','还款只扣账户余额，不会重复计入花销')}<div class="notice">🔔 <span><b>下次还款日：${repaymentDateLabel(next.date)}</b><br>还有 ${next.days} 天 · 每月 ${state.profile.repaymentReminderDay} 号提醒</span></div><div style="height:14px"></div>${groups.map(g=>{let list=debt().filter(t=>t.platform===g),sum=list.reduce((s,t)=>s+t.amount,0),allSelected=list.length&&list.every(t=>selectedDebt.has(t.id));return `<section class="panel debt-group"><div class="debt-head"><b>${escapeHtml(g)}</b><span><b>${money(sum)}</b>${list.length?`<button type="button" data-select-debt-group="${escapeHtml(g)}">${allSelected?'取消全选':'全选'}</button>`:''}</span></div>${list.length?sortedTransactions(list).map(t=>`<label class="check-row"><input type="checkbox" data-debt="${t.id}" ${selectedDebt.has(t.id)?'checked':''}><span><b>${escapeHtml(t.note||t.category)}</b><small>${t.date} · ${escapeHtml(t.category)}</small></span><b>${money(t.amount)}</b></label>`).join(''):'<div class="empty">🎉 暂无待还款</div>'}</section>`}).join('')||'<section class="panel"><div class="empty">请先在账户页面添加月付方式</div></section>'}<div class="form-actions"><span style="margin-right:auto">已选 ${selectedDebt.size} 笔</span><button class="primary" id="repayBtn" ${selectedDebt.size?'':'disabled'}>一键还款</button></div>`}
function budgetPage(){return `${head('类别预算','预算按月计算，每笔花销都会扣减对应类别的剩余预算')}<div class="cards budget-summary"><div class="card"><span class="label">月总预算</span><div class="money">${money(totalBudget())}</div></div><div class="card orange"><span class="label">本月已用</span><div class="money">${money(expense())}</div></div><div class="card ${remainingBudget()<0?'red':'green'}"><span class="label">本月剩余</span><div class="money">${money(remainingBudget())}</div></div></div><section class="panel"><div class="panel-title"><span>📊 ${monthLabel()}预算与类别</span><span>拖动手柄可调整顺序</span></div><div class="panel-body"><form id="categoriesForm"><div class="account-list" id="categoryList">${state.categories.map(c=>{let left=Number(state.budgets[c])-used(c);return `<div class="account manage-row sortable-row category-manage-row" data-sort-category="${escapeHtml(c)}"><span class="manage-name"><span class="drag-handle" title="拖动排序">☰</span><input class="emoji-input" data-category-icon="${escapeHtml(c)}" value="${escapeHtml(categoryIcon(c))}" maxlength="8" aria-label="${escapeHtml(c)}图标"><input data-category-name="${escapeHtml(c)}" value="${escapeHtml(c)}" maxlength="12" aria-label="类别名称"></span><small class="${left<0?'budget-over':''}">已用 ${money(used(c))}</small><span class="balance-input"><span>¥</span><input data-budget="${escapeHtml(c)}" type="number" min="0" step="1" value="${state.budgets[c]}" aria-label="${escapeHtml(c)}预算"></span><button type="button" class="icon-button danger-icon" data-remove-category="${escapeHtml(c)}" title="删除类别">×</button></div>`}).join('')}</div><div class="inline-add category-add"><input id="newCategoryIcon" class="emoji-input" maxlength="8" value="📁" aria-label="新类别图标"><input id="newCategory" maxlength="12" placeholder="新类别名称"><button type="button" class="secondary" id="addCategory">＋ 添加类别</button></div><div class="form-actions"><button type="button" class="primary" id="saveCategories">保存类别与预算</button></div></form></div></section>`}
function accountsPage(){let total=Object.values(state.accounts).reduce((a,b)=>a+b,0),history=state.savingsTransfers.slice(0,8);return `${head('账户与支付方式','管理账户余额、月付方式和存款结转')}<div class="cards"><div class="card"><span class="label">账户总余额</span><div class="money">${money(total)}</div></div><div class="card green"><span class="label">存款余额</span><div class="money">${money(state.savings)}</div></div><div class="card orange"><span class="label">本月结余</span><div class="money">${money(income()-expense())}</div></div><div class="card red"><span class="label">待还负债</span><div class="money">${money(debt().reduce((s,t)=>s+t.amount,0))}</div></div></div><div class="savings-actions"><button class="primary" id="depositSavings">💰 月度结余转存</button><button class="secondary" id="withdrawSavings" ${state.savings>0?'':'disabled'}>↩ 从存款提取</button><button class="secondary" id="editSavings">✎ 修改存款余额</button><span>所有转入、提取和余额修改都需要你确认。</span></div><section class="panel"><div class="panel-title"><span>💳 支付平台 / 入账账户</span><span>拖动手柄可调整顺序</span></div><div class="panel-body"><form id="accountsForm"><div class="account-list" id="platformList">${state.platforms.map(p=>`<div class="account manage-row sortable-row" data-sort-platform="${escapeHtml(p.name)}"><span class="manage-name"><span class="drag-handle" title="拖动排序">☰</span><input data-platform-name="${escapeHtml(p.name)}" value="${escapeHtml(p.name)}" maxlength="16" aria-label="支付方式名称"></span><select data-platform-kind="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}类型"><option value="account" ${p.kind==='account'?'selected':''}>余额账户</option><option value="credit" ${p.kind==='credit'?'selected':''}>月付方式</option></select>${p.kind==='account'?`<span class="balance-input"><span>¥</span><input data-account="${escapeHtml(p.name)}" aria-label="${escapeHtml(p.name)}余额" type="number" step="0.01" value="${Number(state.accounts[p.name]||0).toFixed(2)}" required></span>`:'<span class="status-pill">消费后待还款</span>'}<button type="button" class="icon-button danger-icon" data-remove-platform="${escapeHtml(p.name)}" title="删除支付方式">×</button></div>`).join('')}</div><div class="inline-add"><input id="newPlatform" maxlength="16" placeholder="新支付方式名称"><select id="newPlatformKind"><option value="account">余额账户</option><option value="credit">月付方式</option></select><button type="button" class="secondary" id="addPlatform">＋ 添加</button></div><div class="notice" style="margin-top:14px">💡 余额账户会随收支、还款和存款转账增减；月付消费会进入待还款。</div><div class="form-actions"><button class="primary">保存支付方式</button></div></form></div></section><section class="panel savings-history"><div class="panel-title"><span>📒 存款流水</span><span>最近 ${history.length} 笔</span></div><div class="panel-body">${history.length?history.map(t=>{let meta=savingMeta(t);return `<div class="saving-row"><span>${meta.icon}</span><span><b>${meta.label}</b><small>${t.month?`${monthName(t.month)}结转 · `:''}${escapeHtml(t.account||'手动调整')} · ${t.date}</small></span><b class="${meta.className}">${meta.sign}${money(t.amount)}</b></div>`}).join(''):'<div class="empty">还没有存款转账记录</div>'}</div></section>`}
function profilePage(){return `${head('个人资料','设置在账本中显示的用户名和头像')}<div class="settings-shortcuts"><button class="secondary" data-page="stats">📈 查看收支统计</button><button class="secondary" data-page="budget">📊 管理类别与预算</button><button class="secondary" data-page="accounts">💳 管理支付方式</button></div><section class="panel"><div class="panel-title">👤 我的名片</div><div class="panel-body"><form id="profileForm"><div class="profile-editor"><div class="avatar-picker">${avatarHtml('avatar avatar-large')}<label class="secondary upload-button" for="avatarInput">📷 从相册选择</label><input id="avatarInput" type="file" accept="image/jpeg,image/png,image/webp,image/heic,image/heif" hidden><button type="button" class="secondary ${state.profile.avatar?'':'hidden'}" id="removeAvatar">恢复默认头像</button><small>支持 JPG、PNG、WebP 和 iPhone 相册图片，建议小于 5MB</small></div><div class="field"><label for="profileName">用户名</label><input id="profileName" maxlength="20" value="${escapeHtml(state.profile.name)}" placeholder="请输入用户名" required><small>最多 20 个字符</small></div></div><div class="form-actions"><button class="primary">保存个人资料</button></div></form></div></section>`}
function settingsPage(){let skin=state.profile.skin||'vintage1';return `${head('设置','管理个人资料、还款提醒和界面显示')}<section class="panel settings-panel"><div class="panel-title">⚙ 设置中心</div><div class="settings-body"><aside class="settings-profile">${avatarHtml('avatar avatar-large')}<div><h2>${escapeHtml(state.profile.name)}</h2><p>个人资料</p></div><button class="secondary" data-page="profile">✎ 编辑个人资料</button></aside><form id="settingsForm" class="settings-form"><div class="settings-section-title"><b>还款日期提醒</b><small>设置每月还款日，并同步计算下次还款日期</small></div><div class="field reminder-date-field"><label for="repaymentReminderDay">每月还款日</label><span class="day-input"><span>每月</span><input id="repaymentReminderDay" type="number" min="1" max="31" step="1" value="${state.profile.repaymentReminderDay}" required><span>号</span></span><small>当月没有该日期时，按当月最后一天提醒</small></div><div class="settings-section-title skin-section-title"><b>界面皮肤</b><small>选择你喜欢的显示风格</small></div><div class="skin-options"><button type="button" class="skin-option ${skin==='vintage1'?'selected':''}" data-skin-choice="vintage1" aria-pressed="${skin==='vintage1'}"><span class="skin-preview vintage1-preview"><i></i><b></b><em></em></span><span><b>复古1</b><small>蓝色</small></span></button><button type="button" class="skin-option ${skin==='vintage2'?'selected':''}" data-skin-choice="vintage2" aria-pressed="${skin==='vintage2'}"><span class="skin-preview vintage2-preview"><i></i><b></b><em></em></span><span><b>复古2</b><small>灰银色</small></span></button></div><div class="form-actions"><button type="button" class="primary" id="saveSettings">保存设置</button></div></form></div></section>`}
function platformOptions(kind,selected){return state.platforms.filter(p=>p.kind===kind).map(p=>`<option value="${escapeHtml(p.name)}" ${selected===p.name?'selected':''}>${escapeHtml(p.name)}</option>`).join('')}
function transactionForm(t){let editing=!!t,type=t?.type||'expense',mode=platformKind(t?.platform||'');return `<form id="editTxForm"><div class="choice" id="editTypeChoice"><button type="button" data-value="expense" class="${type==='expense'?'selected':''}">花销</button><button type="button" data-value="income" class="${type==='income'?'selected':''}">收入</button></div><div class="form-grid" style="margin-top:14px"><div class="field full"><label>金额</label><input id="editAmount" type="number" min="0.01" step="0.01" value="${editing?t.amount:''}" required></div><div class="field full" id="editCatField"><label>类别</label><select id="editCategory">${state.categories.map(c=>`<option value="${escapeHtml(c)}" ${t?.category===c?'selected':''}>${escapeHtml(c)}</option>`).join('')}</select></div><div class="field"><label>日期</label><input id="editDate" type="date" value="${t?.date||today()}" required></div><div class="field"><label>时间</label><input id="editTime" type="time" value="${t?.time||new Date().toTimeString().slice(0,5)}" required></div><div class="field full" id="editPayModeField"><label>付款方式</label><select id="editPayMode"><option value="account" ${mode==='account'?'selected':''}>余额支付</option><option value="credit" ${mode==='credit'?'selected':''} ${creditPlatforms().length?'':'disabled'}>月付</option></select></div><div class="field full ${mode==='credit'?'hidden':''}" id="editAccountField"><label id="editAccountLabel">支付平台</label><select id="editAccount">${platformOptions('account',t?.platform)}</select></div><div class="field full ${mode==='credit'?'':'hidden'}" id="editCreditField"><label>选择月付平台</label><select id="editCredit">${platformOptions('credit',t?.platform)}</select></div><div class="field full"><label>备注</label><textarea id="editNote" rows="3">${escapeHtml(t?.note||'')}</textarea></div></div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary">保存修改</button></div></form>`}
function modalHtml(){if(modal==='editSavings')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>✎ 修改存款余额</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="editSavingsForm"><div class="saving-summary">当前存款余额 ${money(state.savings)}</div><div class="field"><label for="editSavingsAmount">新的存款余额</label><input id="editSavingsAmount" type="number" min="0" step="0.01" value="${state.savings}" required></div><div class="notice">这是余额校准，不会改变微信、支付宝或银行卡余额。修改后会记录一笔调整流水。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary">确认修改</button></div></form></div></div></div>`;if(modal==='depositSavings'){let month=previousMonth(),summary=monthlyFinance(month);return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>💰 确认月度结余转存</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="depositForm"><div class="field"><label for="depositMonth">结算月份</label><input id="depositMonth" type="month" max="${previousMonth()}" value="${month}" required></div><div class="saving-summary" id="depositSummary">${monthName(month)}结余 ${money(summary.net)} · 还可转存 ${money(availableToSave(month))}</div><div class="field"><label for="depositAccount">从哪个账户扣款</label><select id="depositAccount" required>${platformOptions('account')}</select></div><div class="field"><label for="depositAmount">确认转存金额</label><input id="depositAmount" type="number" min="0.01" step="0.01" placeholder="0.00" required></div><div class="notice">转存不是花销：确认后只会从所选账户扣除，并增加存款余额。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary" ${accountPlatforms().length?'':'disabled'}>确认转入存款</button></div></form></div></div></div>`}if(modal==='withdrawSavings')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>↩ 确认提取存款</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><form id="withdrawForm"><div class="saving-summary">当前存款余额 ${money(state.savings)}</div><div class="field"><label for="withdrawAccount">提取到哪个账户</label><select id="withdrawAccount" required>${platformOptions('account')}</select></div><div class="field"><label for="withdrawAmount">确认提取金额</label><input id="withdrawAmount" type="number" min="0.01" max="${state.savings}" step="0.01" placeholder="0.00" required></div><div class="notice">确认后，存款余额会减少，所选账户余额会增加。</div><div class="form-actions"><button type="button" class="secondary" id="cancelModal">取消</button><button class="primary" ${accountPlatforms().length&&state.savings>0?'':'disabled'}>确认提取</button></div></form></div></div></div>`;if(modal==='repay')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>💳 确认还款</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><p>选择扣款账户：</p><div class="choice" id="repayAccount">${accountPlatforms().map((p,i)=>`<button data-value="${escapeHtml(p.name)}" class="${i===0?'selected':''}">${escapeHtml(p.name)} · ${money(state.accounts[p.name]||0)}</button>`).join('')}</div><div class="form-actions"><button class="secondary" id="cancelModal">取消</button><button class="primary" id="confirmRepay" ${accountPlatforms().length?'':'disabled'}>确认还款</button></div></div></div></div>`;if(modal?.type==='edit')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>✎ 编辑记录</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body">${transactionForm(state.transactions.find(t=>t.id===modal.id))}</div></div></div>`;if(modal?.type==='delete')return `<div class="modal-wrap"><div class="modal"><div class="titlebar"><span>⚠ 删除记录</span><div class="traffic"><span class="close" id="closeModal">×</span></div></div><div class="body"><p>确定删除这笔记录吗？相关账户余额会同步还原。</p><div class="form-actions"><button class="secondary" id="cancelModal">取消</button><button class="danger" id="confirmDelete">删除记录</button></div></div></div></div>`;return ''}

function render(){let skin=logged?(state.profile.skin||'vintage1'):'vintage1';document.body.dataset.skin=skin;document.body.dataset.page=logged?page:'login';document.body.dataset.layout=logged?'app':'login';document.querySelector('meta[name="theme-color"]')?.setAttribute('content',skin==='vintage2'?'#174991':'#245edb');if(!logged)return login();app.innerHTML=shell();bind()}
function selectIn(container,cb){document.querySelectorAll(`${container} button`).forEach(b=>b.onclick=()=>{document.querySelectorAll(`${container} button`).forEach(x=>x.classList.remove('selected'));b.classList.add('selected');cb?.(b.dataset.value)})}
function submitTransaction(e){e.preventDefault();let type=document.querySelector('#typeChoice .selected')?.dataset.value||'expense',payMode=document.querySelector('#payModeChoice .selected')?.dataset.value||'account',amount=Number(document.querySelector('#amount').value),selectedPlatform=document.querySelector(type==='income'||payMode==='account'?'#accountPlatformChoice .selected':'#creditPlatformChoice .selected'),selectedCategory=document.querySelector('#catChoice .selected');if(!Number.isFinite(amount)||amount<=0){toast('请输入正确的金额');return}if(!selectedPlatform||type==='expense'&&!selectedCategory){toast('请先添加可用的类别和支付方式');return}let platform=selectedPlatform.dataset.value,cat=type==='income'?'收入':selectedCategory.dataset.value,repaid=platformKind(platform)==='account',t={id:Date.now(),type,amount,category:cat,platform,date:document.querySelector('#date').value,time:document.querySelector('#time').value,note:document.querySelector('#note').value.trim(),repaid};state.transactions.unshift(t);adjustBalance(t,1);save();render();toast('记录已保存 ✓')}
function syncAddChoices(button){let group=button.closest('.choice');group.querySelectorAll('button').forEach(item=>item.classList.toggle('selected',item===button));let type=document.querySelector('#typeChoice .selected')?.dataset.value||'expense',payMode=document.querySelector('#payModeChoice .selected')?.dataset.value||'account',incomeMode=type==='income';document.querySelector('#catField')?.classList.toggle('hidden',incomeMode);document.querySelector('#payModeField')?.classList.toggle('hidden',incomeMode);document.querySelector('#accountPlatformField')?.classList.toggle('hidden',!incomeMode&&payMode==='credit');document.querySelector('#creditPlatformField')?.classList.toggle('hidden',incomeMode||payMode!=='credit');let label=document.querySelector('#accountPlatformLabel');if(label)label.textContent=incomeMode?'入账账户':'支付平台'}
function addCategoryFromForm(){let name=document.querySelector('#newCategory')?.value.trim(),icon=document.querySelector('#newCategoryIcon')?.value.trim();if(!name||state.categories.includes(name)){toast(name?'类别名称已存在':'请输入类别名称');return}if(!icon){toast('请输入类别 emoji');return}state.categories.push(name);state.budgets[name]=0;state.categoryIcons[name]=icon;save();render();toast('类别已添加 ✓')}
function submitCategories(e){e.preventDefault();let rows=[...document.querySelectorAll('[data-category-name]')],names=rows.map(input=>input.value.trim()),categoryRows=rows.map(input=>input.closest('.category-manage-row')),categoryIcons=categoryRows.map(row=>row.querySelector('[data-category-icon]').value.trim());if(names.some(name=>!name)||new Set(names).size!==names.length){toast('类别名称不能为空或重复');return}if(categoryIcons.some(icon=>!icon)){toast('类别 emoji 不能为空');return}let nextBudgets={},nextIcons={};rows.forEach((input,index)=>{let old=input.dataset.categoryName,name=names[index],row=categoryRows[index];nextBudgets[name]=Number(row.querySelector('[data-budget]').value);nextIcons[name]=categoryIcons[index];if(old!==name)state.transactions.forEach(transaction=>{if(transaction.category===old)transaction.category=name})});state.categories=names;state.budgets=nextBudgets;state.categoryIcons=nextIcons;save();render();toast('类别、图标与预算已保存 ✓')}
function submitSettings(e){e.preventDefault();let day=Number(document.querySelector('#repaymentReminderDay')?.value);if(!Number.isInteger(day)||day<1||day>31){toast('还款日请输入 1 到 31 的整数');return}state.profile.repaymentReminderDay=day;state.profile.skin=document.querySelector('[data-skin-choice].selected')?.dataset.skinChoice||state.profile.skin||'vintage1';save();render();toast('设置已保存并同步 ✓')}
function enableReorder(containerSelector,itemSelector,keyAttribute,onOrder){let container=document.querySelector(containerSelector);if(!container)return;let dragging=null,changed=false,pointerId=null;let moveTo=(target,y)=>{if(!dragging||!target||target===dragging)return;let rect=target.getBoundingClientRect(),before=y<rect.top+rect.height/2;container.insertBefore(dragging,before?target:target.nextSibling);changed=true};let finish=()=>{if(!dragging)return;dragging.classList.remove('dragging');if(changed)onOrder([...container.querySelectorAll(itemSelector)].map(row=>row.getAttribute(keyAttribute)));dragging=null;changed=false;pointerId=null};container.querySelectorAll(itemSelector).forEach(row=>{let handle=row.querySelector('.drag-handle');handle.onpointerdown=e=>{dragging=row;pointerId=e.pointerId;handle.setPointerCapture?.(e.pointerId);row.classList.add('dragging');e.preventDefault()};handle.onpointermove=e=>{if(pointerId!==e.pointerId||!dragging)return;moveTo(document.elementFromPoint(e.clientX,e.clientY)?.closest(itemSelector),e.clientY);e.preventDefault()};handle.onpointerup=finish;handle.onpointercancel=finish})}
function bind(){document.querySelectorAll('[data-page]').forEach(b=>b.onclick=()=>{if(b.dataset.recordsFilter){recordsMonth=currentMonth();recordsType=b.dataset.recordsFilter;recordsCategory='all'}page=b.dataset.page;render()});document.querySelector('#refreshPage')?.addEventListener('click',async e=>{let button=e.currentTarget;button.disabled=true;if(demoMode){render();toast('页面已刷新 ✓');return}try{if(syncStatus==='等待同步'){clearTimeout(syncTimer);await pushCloud();if(syncStatus==='同步失败')throw new Error('云同步失败，请稍后重试')}await pullCloud();if(matchMedia('(max-width:850px)').matches){sessionStorage.setItem(refreshPageKey,page);location.reload();return}render();toast('已刷新并同步最新数据 ✓')}catch(err){button.disabled=false;toast(`刷新失败：${friendlyError(err)}`)}});document.querySelector('#logout')?.addEventListener('click',async()=>{if(!demoMode){try{await api('/auth/v1/logout',{method:'POST'})}catch{}}session=null;state=freshState();demoMode=false;logged=false;localStorage.removeItem(SESSION_KEY);render()});
  if(page==='add'){let type='expense',payMode='account';let updatePayFields=()=>{let incomeMode=type==='income';document.querySelector('#payModeField').classList.toggle('hidden',incomeMode);document.querySelector('#accountPlatformField').classList.toggle('hidden',!incomeMode&&payMode==='credit');document.querySelector('#creditPlatformField').classList.toggle('hidden',incomeMode||payMode!=='credit');document.querySelector('#accountPlatformLabel').textContent=incomeMode?'入账账户':'支付平台'};selectIn('#typeChoice',v=>{type=v;document.querySelector('#catField').classList.toggle('hidden',v==='income');if(v==='income')payMode='account';updatePayFields()});selectIn('#payModeChoice',v=>{payMode=v;updatePayFields()});selectIn('#catChoice');selectIn('#accountPlatformChoice');selectIn('#creditPlatformChoice');document.querySelector('#saveTransaction').onclick=submitTransaction}
  if(page==='records'){let applyRecordsFilter=e=>{e.preventDefault();recordsMonth=document.querySelector('#recordsMonth').value;recordsType=document.querySelector('#recordsType').value;recordsCategory=document.querySelector('#recordsCategory').value;render()};document.querySelector('#recordsFilterForm').onsubmit=applyRecordsFilter;document.querySelector('#applyRecordsFilter').onclick=applyRecordsFilter;document.querySelectorAll('[data-edit-tx]').forEach(b=>b.onclick=()=>{modal={type:'edit',id:Number(b.dataset.editTx)};render()});document.querySelectorAll('[data-delete-tx]').forEach(b=>b.onclick=()=>{modal={type:'delete',id:Number(b.dataset.deleteTx)};render()})}
  if(page==='stats'){selectIn('#statsMode',v=>{statsMode=v;render()});document.querySelector('#statsMonth')?.addEventListener('change',e=>{statsMonth=e.target.value;render()});document.querySelector('#statsYear')?.addEventListener('change',e=>{statsYear=e.target.value;render()});document.querySelector('#statsStart')?.addEventListener('change',e=>{statsStart=e.target.value;render()});document.querySelector('#statsEnd')?.addEventListener('change',e=>{statsEnd=e.target.value;render()})}
  if(page==='debts'){document.querySelectorAll('[data-debt]').forEach(c=>c.onchange=()=>{let id=Number(c.dataset.debt);c.checked?selectedDebt.add(id):selectedDebt.delete(id);render()});document.querySelectorAll('[data-select-debt-group]').forEach(button=>button.onclick=()=>{let ids=debt().filter(t=>t.platform===button.dataset.selectDebtGroup).map(t=>t.id),allSelected=ids.every(id=>selectedDebt.has(id));ids.forEach(id=>allSelected?selectedDebt.delete(id):selectedDebt.add(id));render()});document.querySelector('#repayBtn')?.addEventListener('click',()=>{modal='repay';render()})}
  if(page==='budget'){enableReorder('#categoryList','[data-sort-category]','data-sort-category',order=>{state.categories=order;save();toast('类别顺序已保存 ✓')});document.querySelector('#addCategory').onclick=()=>{let name=document.querySelector('#newCategory').value.trim(),icon=document.querySelector('#newCategoryIcon').value.trim();if(!name||state.categories.includes(name)){toast(name?'类别名称已存在':'请输入类别名称');return}if(!icon){toast('请输入类别 emoji');return}state.categories.push(name);state.budgets[name]=0;state.categoryIcons[name]=icon;save();render();toast('类别已添加 ✓')};document.querySelectorAll('[data-remove-category]').forEach(b=>b.onclick=()=>{if(state.categories.length===1){toast('至少保留一个类别');return}let name=b.dataset.removeCategory;state.categories=state.categories.filter(c=>c!==name);delete state.budgets[name];delete state.categoryIcons[name];save();render();toast('类别已删除，历史记录仍保留')});let submitCategories=e=>{e.preventDefault();let rows=[...document.querySelectorAll('[data-category-name]')],names=rows.map(i=>i.value.trim()),categoryRows=rows.map(input=>input.closest('.category-manage-row')),categoryIcons=categoryRows.map(row=>row.querySelector('[data-category-icon]').value.trim());if(names.some(n=>!n)||new Set(names).size!==names.length){toast('类别名称不能为空或重复');return}if(categoryIcons.some(icon=>!icon)){toast('类别 emoji 不能为空');return}let nextBudgets={},nextIcons={};rows.forEach((input,i)=>{let old=input.dataset.categoryName,name=names[i],row=categoryRows[i],budget=row.querySelector('[data-budget]');nextBudgets[name]=Number(budget.value);nextIcons[name]=categoryIcons[i];if(old!==name)state.transactions.forEach(t=>{if(t.category===old)t.category=name})});state.categories=names;state.budgets=nextBudgets;state.categoryIcons=nextIcons;save();render();toast('类别、图标与预算已保存 ✓')};document.querySelector('#categoriesForm').onsubmit=submitCategories;document.querySelector('#saveCategories').onclick=submitCategories}
  if(page==='accounts'){document.querySelector('#depositSavings').onclick=()=>{modal='depositSavings';render()};document.querySelector('#withdrawSavings').onclick=()=>{modal='withdrawSavings';render()};enableReorder('#platformList','[data-sort-platform]','data-sort-platform',order=>{state.platforms=order.map(name=>state.platforms.find(p=>p.name===name)).filter(Boolean);save();toast('支付方式顺序已保存 ✓')});document.querySelector('#addPlatform').onclick=()=>{let name=document.querySelector('#newPlatform').value.trim(),kind=document.querySelector('#newPlatformKind').value;if(!name||state.platforms.some(p=>p.name===name)){toast(name?'支付方式名称已存在':'请输入支付方式名称');return}state.platforms.push({name,kind});if(kind==='account')state.accounts[name]=0;save();render();toast('支付方式已添加 ✓')};document.querySelectorAll('[data-remove-platform]').forEach(b=>b.onclick=()=>{if(state.platforms.length===1){toast('至少保留一种支付方式');return}let name=b.dataset.removePlatform;state.platforms=state.platforms.filter(p=>p.name!==name);delete state.accounts[name];save();render();toast('支付方式已删除，历史记录仍保留')});document.querySelector('#accountsForm').onsubmit=e=>{e.preventDefault();let rows=[...document.querySelectorAll('[data-platform-name]')],names=rows.map(i=>i.value.trim());if(names.some(n=>!n)||new Set(names).size!==names.length){toast('支付方式名称不能为空或重复');return}let oldAccounts={...state.accounts},nextAccounts={},nextPlatforms=[];rows.forEach((input,i)=>{let old=input.dataset.platformName,name=names[i],row=input.closest('.manage-row'),kind=row.querySelector('[data-platform-kind]').value,balance=row.querySelector('[data-account]');nextPlatforms.push({name,kind});if(kind==='account')nextAccounts[name]=balance?Number(balance.value):Number(oldAccounts[old]||0);if(old!==name){state.transactions.forEach(t=>{if(t.platform===old)t.platform=name;if(t.repaidAccount===old)t.repaidAccount=name});state.savingsTransfers.forEach(t=>{if(t.account===old)t.account=name})}});state.platforms=nextPlatforms;state.accounts=nextAccounts;save();render();toast('支付方式已保存并同步 ✓')}}
  if(page==='profile'){let pendingAvatar=state.profile.avatar;document.querySelector('#avatarInput').onchange=e=>{let file=e.target.files?.[0];if(!file)return;if(file.size>8*1024*1024){toast('图片不能超过 8MB');e.target.value='';return}let reader=new FileReader();reader.onload=()=>{let img=new Image();img.onload=()=>{let size=256,canvas=document.createElement('canvas');canvas.width=size;canvas.height=size;let ctx=canvas.getContext('2d'),side=Math.min(img.width,img.height),sx=(img.width-side)/2,sy=(img.height-side)/2;ctx.drawImage(img,sx,sy,side,side,0,0,size,size);pendingAvatar=canvas.toDataURL('image/jpeg',.82);let box=document.querySelector('.avatar-large');box.innerHTML=`<img src="${pendingAvatar}" alt="头像预览">`;document.querySelector('#removeAvatar').classList.remove('hidden')};img.onerror=()=>toast('无法读取这张图片，请尝试 JPG 或 PNG');img.src=reader.result};reader.readAsDataURL(file)};document.querySelector('#removeAvatar')?.addEventListener('click',()=>{pendingAvatar='';document.querySelector('.avatar-large').innerHTML='🐷';document.querySelector('#removeAvatar').classList.add('hidden')});document.querySelector('#profileForm').onsubmit=e=>{e.preventDefault();let name=document.querySelector('#profileName').value.trim();if(!name)return;state.profile={...state.profile,name,avatar:pendingAvatar};save();render();toast('个人资料已保存并同步 ✓')}}
  if(page==='my'||page==='settings'){let submitSettings=e=>{e.preventDefault();let day=Number(document.querySelector('#repaymentReminderDay').value);if(!Number.isInteger(day)||day<1||day>31){toast('还款日请输入 1 到 31 的整数');return}state.profile.repaymentReminderDay=day;state.profile.skin=document.querySelector('[data-skin-choice].selected')?.dataset.skinChoice||'vintage1';save();render();toast('设置已保存并同步 ✓')};document.querySelector('#settingsForm').onsubmit=submitSettings;document.querySelector('#saveSettings').onclick=submitSettings}
  if(modal){let close=()=>{modal=null;render()};document.querySelector('#closeModal').onclick=close;document.querySelector('#cancelModal').onclick=close;if(modal==='depositSavings'){let monthInput=document.querySelector('#depositMonth'),accountInput=document.querySelector('#depositAccount'),amountInput=document.querySelector('#depositAmount'),updateSummary=()=>{let month=monthInput.value,available=availableToSave(month),account=accountInput.value,balance=Number(state.accounts[account]||0);document.querySelector('#depositSummary').textContent=`${monthName(month)}结余 ${money(monthlyFinance(month).net)} · 还可转存 ${money(available)} · ${account}余额 ${money(balance)}`;amountInput.max=Math.min(available,balance)};monthInput.onchange=updateSummary;accountInput.onchange=updateSummary;updateSummary();document.querySelector('#depositForm').onsubmit=e=>{e.preventDefault();let month=monthInput.value,account=accountInput.value,amount=Number(amountInput.value),available=availableToSave(month),balance=Number(state.accounts[account]||0);if(amount<=0){toast('请输入正确的转存金额');return}if(amount>available){toast(`该月最多还可转存 ${money(available)}`);return}if(amount>balance){toast(`${account}余额不足，当前可用 ${money(balance)}`);return}state.accounts[account]-=amount;state.savings+=amount;state.savingsTransfers.unshift({id:Date.now(),type:'deposit',amount,account,month,date:today()});modal=null;save();render();toast(`${monthName(month)}已转存 ${money(amount)} ✓`)}}else if(modal==='withdrawSavings'){document.querySelector('#withdrawForm').onsubmit=e=>{e.preventDefault();let account=document.querySelector('#withdrawAccount').value,amount=Number(document.querySelector('#withdrawAmount').value);if(amount<=0){toast('请输入正确的提取金额');return}if(amount>state.savings){toast(`存款余额不足，当前可用 ${money(state.savings)}`);return}state.savings-=amount;state.accounts[account]=Number(state.accounts[account]||0)+amount;state.savingsTransfers.unshift({id:Date.now(),type:'withdrawal',amount,account,date:today()});modal=null;save();render();toast(`已提取 ${money(amount)} 到${account} ✓`)}}else if(modal==='repay'){selectIn('#repayAccount');document.querySelector('#confirmRepay').onclick=()=>{let selected=document.querySelector('#repayAccount .selected');if(!selected)return;let acc=selected.dataset.value,total=0;state.transactions.forEach(t=>{if(selectedDebt.has(t.id)){t.repaid=true;t.repaidAccount=acc;total+=t.amount}});state.accounts[acc]-=total;selectedDebt.clear();modal=null;save();render();toast(`还款 ${money(total)} 成功 ✓`)}}else if(modal.type==='edit'){let t=state.transactions.find(x=>x.id===modal.id),type=t.type;let updateEditPayFields=()=>{let mode=type==='income'?'account':document.querySelector('#editPayMode').value;document.querySelector('#editPayModeField').classList.toggle('hidden',type==='income');document.querySelector('#editAccountField').classList.toggle('hidden',mode==='credit');document.querySelector('#editCreditField').classList.toggle('hidden',mode!=='credit');document.querySelector('#editAccountLabel').textContent=type==='income'?'入账账户':'支付平台'};selectIn('#editTypeChoice',v=>{type=v;document.querySelector('#editCatField').classList.toggle('hidden',v==='income');updateEditPayFields()});document.querySelector('#editPayMode').onchange=updateEditPayFields;document.querySelector('#editCatField').classList.toggle('hidden',type==='income');updateEditPayFields();document.querySelector('#editTxForm').onsubmit=e=>{e.preventDefault();let old={...t},mode=type==='income'?'account':document.querySelector('#editPayMode').value,platform=document.querySelector(mode==='credit'?'#editCredit':'#editAccount').value;if(!platform){toast('请先添加对应的支付方式');return}adjustBalance(old,-1);let wasSamePaidCredit=old.type==='expense'&&old.repaid&&platformKind(old.platform)==='credit'&&old.platform===platform,repaid=type==='income'||platformKind(platform)==='account'||wasSamePaidCredit;Object.assign(t,{type,amount:Number(document.querySelector('#editAmount').value),category:type==='income'?'收入':document.querySelector('#editCategory').value,platform,date:document.querySelector('#editDate').value,time:document.querySelector('#editTime').value,note:document.querySelector('#editNote').value.trim(),repaid});if(!wasSamePaidCredit)delete t.repaidAccount;adjustBalance(t,1);modal=null;save();render();toast('记录已修改 ✓')}}else if(modal.type==='delete'){document.querySelector('#confirmDelete').onclick=()=>{let index=state.transactions.findIndex(t=>t.id===modal.id),t=state.transactions[index];if(index<0)return;adjustBalance(t,-1);state.transactions.splice(index,1);selectedDebt.delete(t.id);modal=null;save();render();toast('记录已删除 ✓')}}}
}
function toast(msg){let el=document.createElement('div');el.className='toast';el.textContent=msg;document.body.append(el);setTimeout(()=>el.remove(),3200)}
document.addEventListener('pointerdown',e=>{let field=e.target.closest('input,textarea,select');if(field&&!field.disabled)field.focus()},{capture:true})
document.addEventListener('mousedown',e=>{let field=e.target.closest('input,textarea,select');if(field&&!field.disabled)field.focus()},{capture:true})
document.addEventListener('click',e=>{let debtCheckbox=e.target.closest('[data-debt]');if(debtCheckbox){e.preventDefault();e.stopImmediatePropagation();let id=Number(debtCheckbox.dataset.debt);selectedDebt.has(id)?selectedDebt.delete(id):selectedDebt.add(id);render();return}if(e.target.closest('#saveCategories')){e.preventDefault();e.stopImmediatePropagation();submitCategories(e);return}if(e.target.closest('#saveSettings')){e.preventDefault();e.stopImmediatePropagation();submitSettings(e);return}let field=e.target.closest('input,textarea,select');if(field&&!field.disabled){field.focus();return}let addChoice=e.target.closest('#txForm .choice button[data-value]');if(addChoice){e.preventDefault();e.stopImmediatePropagation();syncAddChoices(addChoice);return}if(e.target.closest('#addCategory')){e.preventDefault();e.stopImmediatePropagation();addCategoryFromForm()}},{capture:true})
document.addEventListener('change',e=>{let checkbox=e.target.closest('[data-debt]');if(!checkbox)return;e.stopImmediatePropagation();let id=Number(checkbox.dataset.debt);checkbox.checked?selectedDebt.add(id):selectedDebt.delete(id);render()},{capture:true})
document.addEventListener('submit',e=>{if(e.target.id==='categoriesForm'){e.stopImmediatePropagation();submitCategories(e)}else if(e.target.id==='settingsForm'){e.stopImmediatePropagation();submitSettings(e)}},{capture:true})
document.addEventListener('click',e=>{let skinChoice=e.target.closest('[data-skin-choice]');if(skinChoice){let value=skinChoice.dataset.skinChoice;if(!['vintage1','vintage2'].includes(value)||state.profile.skin===value)return;let reminderInput=document.querySelector('#repaymentReminderDay'),day=Number(reminderInput?.value);if(Number.isInteger(day)&&day>=1&&day<=31)state.profile.repaymentReminderDay=day;state.profile.skin=value;save();render();toast(`已切换到${value==='vintage2'?'复古2':'复古1'} ✓`)}else if(e.target.closest('#depositSavings')){modal='depositSavings';render()}else if(e.target.closest('#withdrawSavings')){modal='withdrawSavings';render()}else if(e.target.closest('#editSavings')){modal='editSavings';render()}})
document.addEventListener('submit',e=>{if(e.target.id==='txForm')submitTransaction(e)})
document.addEventListener('submit',e=>{if(e.target.id!=='editSavingsForm')return;e.preventDefault();let next=Number(document.querySelector('#editSavingsAmount').value),old=state.savings;if(!Number.isFinite(next)||next<0){toast('请输入正确的存款余额');return}if(next!==old)state.savingsTransfers.unshift({id:Date.now(),type:'adjustment',direction:next>old?'increase':'decrease',amount:Math.abs(next-old),account:'手动调整',date:today()});state.savings=next;modal=null;save();render();toast(`存款余额已修改为 ${money(next)} ✓`)})
async function bootstrap(){if(session?.refresh_token&&session.expires_at<Date.now()/1000+60){try{let data=await api('/auth/v1/token?grant_type=refresh_token',{method:'POST',body:JSON.stringify({refresh_token:session.refresh_token})});session={...data,expires_at:Math.floor(Date.now()/1000)+data.expires_in};localStorage.setItem(SESSION_KEY,JSON.stringify(session))}catch{session=null;logged=false;localStorage.removeItem(SESSION_KEY)}}if(session){try{await pullCloud();syncStatus='已同步'}catch(e){syncStatus='同步失败';setTimeout(()=>toast(`云同步失败：${friendlyError(e)}`),100)}}render()}
bootstrap()
